-- Oceania: admin1 (dr5hn ODbL) + cities (SimpleMaps CC BY 4.0), canon schema
ON CONFLICT (id) DO NOTHING;

-- coord backfill for pre-existing admin1
UPDATE atoms a SET geo = a.geo || jsonb_build_object('lat',d.lat,'lng',d.lng), updated_at=now()
FROM (VALUES ('AU-ACT',-35.4883502,149.0026942),('AU-NSW',-31.8759835,147.2869493),('AU-NT',-19.8516101,133.2303375),('AU-QLD',-22.1646782,144.5844903),('AU-SA',-30.5343665,135.6301212),('AU-TAS',-42.035067,146.6366887),('AU-VIC',-36.5986096,144.6780052),('AU-WA',-25.2303005,121.0187246)) AS d(rid,lat,lng)
WHERE a.realm_id='geography' AND a.type='admin1' AND a.geo->>'regionId'=d.rid AND NOT (a.geo ? 'lat');

ON CONFLICT (id) DO NOTHING;

-- flip is_leaf on countries/admin1 that gained children
UPDATE atoms a SET is_leaf=false, updated_at=now()
WHERE a.realm_id='geography' AND a.depth IN (4,5) AND a.path LIKE 'Geography / Countries / Oceania / %'
  AND EXISTS (SELECT 1 FROM atoms c WHERE c.path LIKE a.path || ' / %');